mapper.select:
/* AccountingMainMapper.getAcDayTransferList */ SELECT TO_CHAR(TO_DATE(A.SALE_DATE, 'yyyymmdd'), 'yyyy-mm-dd') AS SALE_DATE , TO_CHAR(TO_DATE(A.SALE_DATE, 'YYYYMMDD'), 'DY') AS YOIL , A.STORE_CD , B.STORE_NM , A.TOT_SALE_AMT , A.TOT_DC_AMT , A.REAL_SALE_AMT , A.BILL_CNT , DECODE(A.BILL_CNT, 0, 0, ROUND(A.REAL_SALE_AMT / A.BILL_CNT)) AS BILL_UPRC , A.REAL_SALE_AMT - A.VAT_AMT AS GA_AMT , A.VAT_AMT , A.TOT_TIP_AMT , A.TOT_ETC_AMT , A.CUP_AMT FROM TB_SL_DAILY_TOTAL A , TB_MS_STORE B , TB_AC_STORE_OPTION C WHERE 1=1 AND B.STORE_CD = A.STORE_CD AND C.STORE_CD (+) = A.STORE_CD AND A.HQ_OFFICE_CD = #{hqOfficeCd} AND A.SALE_DATE BETWEEN #{startDate} AND #{endDate}
AND A.STORE_CD IN (${storeCdQuery})
AND C.OPTION01 LIKE '%' || #{option01} || '%'
AND C.OPTION02 = #{option02}
AND NVL(C.OPTION03, 'N') = #{option03}
AND C.OPTION04 LIKE '%' || #{option04} || '%'
ORDER BY A.SALE_DATE , A.STORE_CD

/* AccountingMainMapper.getAcMonthTransferList */ SELECT TO_CHAR(TO_DATE(A.SALE_YM, 'yyyymm'), 'yyyy-mm') AS SALE_YM , A.STORE_CD , B.STORE_NM , A.TOT_SALE_AMT , A.TOT_DC_AMT , A.REAL_SALE_AMT , A.BILL_CNT , DECODE(A.BILL_CNT, 0, 0, ROUND(A.REAL_SALE_AMT / A.BILL_CNT)) AS BILL_UPRC , A.REAL_SALE_AMT - A.VAT_AMT AS GA_AMT , A.VAT_AMT , A.TOT_TIP_AMT , A.TOT_ETC_AMT , A.CUP_AMT FROM TB_SL_MONTHLY_TOTAL A , TB_MS_STORE B , TB_AC_STORE_OPTION C WHERE 1=1 AND B.STORE_CD = A.STORE_CD AND C.STORE_CD (+) = A.STORE_CD AND A.HQ_OFFICE_CD = #{hqOfficeCd} AND A.SALE_YM BETWEEN #{startMonth} AND #{endMonth}
AND A.STORE_CD IN (${storeCdQuery})
AND C.OPTION01 LIKE '%' || #{option01} || '%'
AND C.OPTION02 = #{option02}
AND NVL(C.OPTION03, 'N') = #{option03}
AND C.OPTION04 LIKE '%' || #{option04} || '%'
ORDER BY A.SALE_YM , A.STORE_CD

/* AccountingMainMapper.getAcStoreOptionList */ SELECT A.HQ_OFFICE_CD , A.STORE_CD , A.STORE_NM , B.OPTION01 , B.OPTION02 , NVL(B.OPTION03, 'N') AS option03 , B.OPTION04 , B.OPTION05 , B.OPTION06 , B.OPTION07 , B.OPTION08 , B.OPTION09 , B.OPTION10 , B.OPTION11 , B.OPTION12 , B.OPTION13 , B.OPTION14 , B.OPTION15 , B.OPTION16 , B.OPTION17 , B.OPTION18 , B.OPTION19 , B.OPTION20 FROM TB_MS_STORE A , TB_AC_STORE_OPTION B WHERE 1=1 AND B.STORE_CD (+) = A.STORE_CD AND A.HQ_OFFICE_CD = #{hqOfficeCd}
AND A.STORE_CD IN (${storeCdQuery})
AND B.OPTION01 LIKE '%' || #{option01} || '%'
AND B.OPTION02 = #{option02}
AND NVL(B.OPTION03, 'N') = #{option03}
AND B.OPTION04 LIKE '%' || #{option04} || '%'
ORDER BY A.STORE_CD

mapper.update:
/* USE : AccountingMainMapper.saveAcStoreOption */
MERGE INTO TB_AC_STORE_OPTION A
USING DUAL
ON  (
            HQ_OFFICE_CD    =   #{hqOfficeCd}
        AND STORE_CD        =   #{storeCd}
    )
WHEN MATCHED THEN
UPDATE
SET
    OPTION01    =   #{option01}
,   OPTION02    =   #{option02}
,   OPTION03    =   #{option03}
,   OPTION04    =   #{option04}
,   MOD_DT      =   #{modDt}
,   MOD_ID      =   #{modId}
WHEN NOT MATCHED THEN
INSERT
(
        HQ_OFFICE_CD
,       STORE_CD
,       OPTION01
,       OPTION02
,       OPTION03
,       OPTION04
,       REG_DT
,       REG_ID
,       MOD_DT
,       MOD_ID
)
VALUES
(
        #{hqOfficeCd}
,       #{storeCd}
,       #{option01}
,       #{option02}
,       #{option03}
,       #{option04}
,       #{regDt}
,       #{regId}
,       #{modDt}
,       #{modId}
)

mapper.delete:
/* USE : AccountingMainMapper.delAcStoreOption */
DELETE
FROM    TB_AC_STORE_OPTION A
WHERE   A.HQ_OFFICE_CD  =   #{hqOfficeCd}
AND     A.STORE_CD      =   #{storeCd}

