/* USE : AccountingMainMapper.saveAcComCodeUpdate */
UPDATE  TB_AC_HQ_NMCODE
SET
        AC_NMCODE_NM    =   #{acNmcodeNm}
,       AC_NMCODE_ETC01 =   #{acNmcodeEtc01,jdbcType=VARCHAR}
,       AC_NMCODE_ETC02 =   #{acNmcodeEtc02,jdbcType=VARCHAR}
,       AC_NMCODE_ETC03 =   #{acNmcodeEtc03,jdbcType=VARCHAR}
,       USE_YN          =   #{useYn}
,       MOD_DT          =   #{modDt}
,       MOD_ID          =   #{modId}
WHERE   HQ_OFFICE_CD    =   #{hqOfficeCd}
AND     AC_NMCODE_CD    =   #{acNmcodeCd}

